class t{constructor(){this.accordions=document.querySelectorAll(".accordion"),this.accordions.length>0&&this.init()}init(){this.accordions.forEach(t=>{this.initAccordion(t)})}initAccordion(t){const e=t.querySelectorAll(".accordion__item");e&&0!==e.length&&e.forEach(t=>{const e=t.querySelector(".accordion__trigger"),i=t.querySelector(".accordion__content");e&&i&&e.addEventListener("click",()=>{t.classList.contains("is-active")?(t.classList.remove("is-active"),e.setAttribute("aria-expanded","false"),i.style.maxHeight=null):(t.classList.add("is-active"),e.setAttribute("aria-expanded","true"),i.style.maxHeight=i.scrollHeight+"px")})})}}export{t as default};
